# Removes zero rows from triagonal matrix to avoid problems in further processing, returns the matrix

remove_zero_rows := proc(M)
 local rows, nonzero, i, j:

 rows := RowDimension(M):
 nonzero := []:

 for i from 1 to rows do
  if not evalb(add(abs(M[i,j]), j=1..ColumnDimension(M)) = 0) then
   nonzero := [op(nonzero), i];
  fi:
 od:

 return M[nonzero, ..]:
end proc:



solve_sector := proc(sector)
 local branch, rules, new_rules, b, r, c, all_rules, rule, cond, new_branches, rules_and_conds:
 local final_result, i, next_branch:

 rules_and_conds := []:
 final_result := []:

 branch := []:
 i := 1:

 branch, rule, cond := op(find_rule_for_branch(sector, branch)):

 # Maybe have to modify this rules cond if sector isn't top one. Have to modify applicability_conditions

 rules_and_conds := [op(rules_and_conds), [rule, branch, cond]]:

 # Figure out which indices are potentially problematic
 
 if cond = [] and sector = [1,1,1,1,1] then 
  print("sector solved with first rule"):
  return rules_and_conds:
 fi:

 #print("in solved sector after first run", rules_and_conds):
 
 new_branches := add_branch_cond(branch, cond):
 
 local branches_to_add:
 
 while not solved(sector, branch, cond) or i <= nops(new_branches) do
  #print("branch,rule and cond", branch, rule, cond):
  #print("how many branches I have", nops(new_branches)):
  next_branch := new_branches[i]:
  
  if nops(next_branch) = 5 then 
   #print("reached fully numeric cases"):     
   #print("branches are", new_branches):
   local full_branch:
    for full_branch in new_branches do
       if nops(full_branch) = 5 then
         branch, rule, cond := op(find_rule_for_numeric_case(sector, full_branch)):

         if not (branch = 0 and rule = 0 and cond = 0) then
          rules_and_conds := [op(rules_and_conds), [rule, branch, cond]]:
         fi:
       fi:
    od:
    return rules_and_conds:
  fi: 
  
  #print("next branch", next_branch):
  #print("_______________next branch______________________", next_branch):
  branch, rule, cond := op(find_rule_for_branch(sector, next_branch)):
  print("rule", rule):
  rules_and_conds := [op(rules_and_conds), [rule, branch, cond]]:

  branches_to_add := add_branch_cond(branch, cond):
  #print("branches to add", branches_to_add):
  if branches_to_add <> 0 then
   new_branches := [op(new_branches), op(branches_to_add)]:
  fi:
  #print("new branches are", new_branches):
  new_branches := MakeUnique(map(L -> sort(L), new_branches)):
  #print("unique branches are", new_branches):
  i := i+1:
 od:

 return rules_and_conds:
end proc:   



solved := proc(sector, branch, cond)
 local nus, lhs_branches, lhs_cond, lhs_branches_set, pot_new_branch, c, b, i, lhs_c, nondet, cond_nus, tmp:
 local branch_from_cond, lhs_b, j:
 

 nus := [nu1, nu2, nu3, nu4, nu5]:
 lhs_branches_set := {}:
 lhs_branches := []:
 lhs_cond := []:
 pot_new_branch := []:

 #print("cond in solved", cond):
 
 # I think this can only happen when I have a zero operator on lhs
 if cond = [] and sector = [1,1,1,1,1] then 
  #print("check if lhs is zero operator"):
  return true:
 elif cond = [] then 
  return true:
 fi:

 for b in branch do
  lhs_b:= op(indets(lhs(b))):
  lhs_branches := [op(lhs_branches), lhs_b]:
 od:
 
 lhs_branches_set := convert(lhs_branches, set):

 # Probably unneccessary, since I check number of nondets below
 if nops(cond) > 1 then
  for c in cond do 
   tmp := indets(op(c)) intersect convert(nus, set):
   cond_nus := cond_nus union tmp:
  od:
 elif nops(op(cond)) = 1 then
  cond_nus := indets(op(op(cond))) intersect convert(nus, set):
 else 
  for j from 1 to nops(op(cond)) do
   tmp := indets(op(c)[j]) intersect convert(nus, set):
   cond_nus := cond_nus union tmp:
  od:
 fi:
 nondet := nops(cond_nus):
 

 # this way, becasue if I have a condition like nu1 + nu3 - 2 <> 0 then only nu3 is undetermined
 if nondet - 1 > 0 then
  #print("not every index is determined"):
  return false:
 fi:
 
 if (nops(lhs_branches_set) + nondet <> nops(nus)) or (cond_nus intersect lhs_branches_set <> {}) then
  #print("have to further branch or am not at the end yet"):
  return false:
 fi:
 #print("default true"):
 return true:
end proc:



find_rule_for_numeric_case := proc(sector, branch)
 local i, triag, ints, mat, rule, cond, old_branch:
 local found, seeds, seed, depth, rules, old_ibps, new_ibps, nu, b, sig, j:

 #print("branch", branch):

 if nops(branch) <> 5 then
  error "This branch is not fully determined":
  return 0:
 fi: 

 found := false:
 depth := 1:
 seed := [0,0,0,0,0]:
 nu := [nu1, nu2, nu3, nu4, nu5]:

 for b in branch do
  nu := algsubs(b, nu):
 od: 
 #print("branched nus", nu):

 sig := index_signature(sector, nu):
 #print("signature", sig):

 old_ibps := create_branch_ibps(branch, seed):
 #print("branched ibps", old_ibps):

 mat := get_final_matrix(sector, old_ibps):
 triag := mat[3]:
 triag := remove_zero_rows(triag):
 ints := mat[4]:
 #print("matrix is", triag, ints):

 # I need to run filter_branched_rules to determine if there is a rule before I seed
  #print("before seeding at this branch"):
  old_branch, rule, cond := filter_branched_rules(sector, triag, ints, branch):
  #print("first rule in find branch rules", rule):
  #print("first cond in find branch rules", cond):
  if (rule <> 0) then 
   #print("rule not zero"):
   rules := [branch, rule, cond]:
   #print("return", rules):
   return rules:
  fi:

  #print("start seeding ibps"):

  local count: 
  count := 1: 

 if (cond = [] and rule = 0) then
  while not found do
   if depth > 2 then
    print("depth limit of 2 reached in numeric cases"):
    return [0,0,0]:
    break:
   fi:
   seeds := create_all_shifts(sector, depth):
   #print("the total number of seeds is", nops(seeds)):

   # Maybe here filter out seeds that jump the sector border (?)

   for seed in seeds do
    #print("depth is", depth):
    #print("seed", seed):
    new_ibps := create_branch_ibps(branch, seed):
    #print("branched ibps in seed",seed, branch, "are", new_ibps):
    #print("new ibp matrix", get_final_matrix(sector, [op(new_ibps)])[3]):
    mat := get_final_matrix(sector, [op(old_ibps), op(new_ibps)]):
    triag := mat[3]:
    ints := mat[4]:
    #print("matrix in",branch,"with seed", seed, " is", triag, ints):
    triag := remove_zero_rows(triag):
    #print(triag, ints):
    #print("matrix in",branch,"with seed", seed, " is", triag, ints):
    #print(member(0, convert(MatrixVectorMultiply(triag, ints), set))):
    old_branch, rule, cond := filter_branched_rules(sector, triag, ints, branch):
    if (rule <> 0) then 
      found := true:
      rules := [old_branch, rule, cond]:
      break:
    fi:
    old_ibps := [op(old_ibps), op(new_ibps)]:
    count := count +1: 
   od:
   depth := depth + 1:
  od:
 fi:
 return rules:

end proc:



return_sector_rules := proc(solution)
  local cur, rule, i, r,t:

  #print("solution is", solution):

  rule := []:

  for i from 1 to nops(solution) do
   cur := solution[i, 1]:
   #r, t := simplify_coeffs(cur):
   #print("the simplified coeff rule is", r):
   rule := [op(rule),cur]:
  od:

  #print("rules in combine", rule):
