simplify_coeffs := proc(eq)
local lhs_expr, rhs_expr, lhs_SCs, rhs_SCs, coeff_tab, s, c, new_lhs, new_rhs, neweq, i, k, ai, coeff_list:

lhs_expr := lhs(eq):
rhs_expr := rhs(eq):

if type(lhs_expr, `*`) and type(rhs_expr, `*`) and
   denom(lhs_expr) <> 1 and simplify(denom(lhs_expr)/denom(rhs_expr)) = 1 then
    lhs_expr := numer(lhs_expr):
    rhs_expr := numer(rhs_expr):
fi:

lhs_expr := expand(lhs_expr):
rhs_expr := expand(rhs_expr):

lhs_SCs := sort([op(indets(lhs_expr, specfunc(anything, SC)))]):
rhs_SCs := sort([op(indets(rhs_expr, specfunc(anything, SC)))]):

coeff_tab := table():

i := 1:

new_lhs := 0:
for s in lhs_SCs do
    c := coeff(lhs_expr, s):
    c := expand(c):
    c := normal(c):
    c := simplify(c, symbolic):
    c := factor(c):
    c := collect(c, [Q, M1, M3, M5, nu2, nu4, D], factor):

    ai := parse(cat("a", i)):
    coeff_tab[ai] := c:

    new_lhs := new_lhs + ai*s:

    i := i + 1:
od:

new_rhs := 0:
for s in rhs_SCs do
    c := coeff(rhs_expr, s):
    c := expand(c):
    c := normal(c):
    c := simplify(c, symbolic):
    c := factor(c):
    c := collect(c, [Q, M1, M3, M5, nu2, nu4, D], factor):

    ai := parse(cat("a", i)):
    coeff_tab[ai] := c:

    new_rhs := new_rhs + ai*s:

    i := i + 1:
od:

neweq := new_lhs = new_rhs:
#print("new eq is", neweq):

coeff_list := []:
#print("lhs sc is", lhs_SCs):


local keys, sorted_keys, sorted_pairs, key_pairs:

keys := [indices(coeff_tab)]:
keys := map(x -> op(1, x), keys):

key_pairs := map(k -> [parse(substring(convert(k, string), 2..-1)), k], keys);

sorted_pairs := sort(key_pairs, (x, y) -> x[1] < y[1]);

sorted_keys := map(x -> x[2], sorted_pairs);

#print("sorted coeffs", sorted_keys):

for k in sorted_keys do
    coeff_list := [op(coeff_list), k = coeff_tab[k]]:
od:

#print("before returning results"):
return neweq,  eval(coeff_list):

end proc: 



